import{_ as a,o,c as s,au as t}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Composables","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/composables.md","filePath":"api/core/composables.md"}'),r={name:"api/core/composables.md"};function l(c,e,i,n,h,m){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="composables" tabindex="-1">Composables <a class="header-anchor" href="#composables" aria-label="Permalink to &quot;Composables&quot;">​</a></h1><h2 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h2><h3 id="usestore" tabindex="-1"><a href="./composables/composables.store.html">useStore</a> <a class="header-anchor" href="#usestore" aria-label="Permalink to &quot;[useStore](./composables/composables.store.md)&quot;">​</a></h3><p>Used to setup a named reactive store backed by Vue&#39;s <code>reactive()</code>. All stores share a single global registry; calling <code>useStore</code> with the same name from multiple components returns the same reactive object.</p><h2 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to &quot;Version&quot;">​</a></h2><h3 id="useversion" tabindex="-1"><a href="./composables/composables.version.html">useVersion</a> <a class="header-anchor" href="#useversion" aria-label="Permalink to &quot;[useVersion](./composables/composables.version.md)&quot;">​</a></h3><p>Exposes read-only access to the client and API version information. On first call it fetches the API version from the <code>Capabilities</code> singleton.</p><h2 id="user-session" tabindex="-1">User &amp; Session <a class="header-anchor" href="#user-session" aria-label="Permalink to &quot;User &amp; Session&quot;">​</a></h2><h3 id="useuser" tabindex="-1"><a href="./composables/composables.user.html">useUser</a> <a class="header-anchor" href="#useuser" aria-label="Permalink to &quot;[useUser](./composables/composables.user.md)&quot;">​</a></h3><p>Provides reactive access to the currently authenticated user (<code>name</code>, <code>description</code>, <code>avatar</code>, <code>role</code>) read directly from the global KDK store.</p><h3 id="usesession" tabindex="-1"><a href="./composables/composables.session.html">useSession</a> <a class="header-anchor" href="#usesession" aria-label="Permalink to &quot;[useSession](./composables/composables.session.md)&quot;">​</a></h3><p>Manages the full client session lifecycle: restoring an existing session on mount, redirecting based on route guards and user abilities, and handling socket disconnection/reconnection events with appropriate UI prompts.</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><h3 id="usecontext" tabindex="-1"><a href="./composables/composables.context.html">useContext</a> <a class="header-anchor" href="#usecontext" aria-label="Permalink to &quot;[useContext](./composables/composables.context.md)&quot;">​</a></h3><p>Manages the current application context (e.g. an organisation or project). Keeps the context in sync with the backend via service events and redirects to a fallback route when the context is deleted.</p><h2 id="selection" tabindex="-1">Selection <a class="header-anchor" href="#selection" aria-label="Permalink to &quot;Selection&quot;">​</a></h2><h3 id="useselection" tabindex="-1"><a href="./composables/composables.selection.html">useSelection</a> <a class="header-anchor" href="#useselection" aria-label="Permalink to &quot;[useSelection](./composables/composables.selection.md)&quot;">​</a></h3><p>Creates or retrieves a named reactive selection store. Supports single/multiple selection modes, optional item filtering, and configurable item comparison.</p><h2 id="screen-layout" tabindex="-1">Screen &amp; Layout <a class="header-anchor" href="#screen-layout" aria-label="Permalink to &quot;Screen &amp; Layout&quot;">​</a></h2><h3 id="usescreen" tabindex="-1"><a href="./composables/composables.screen.html">useScreen</a> <a class="header-anchor" href="#usescreen" aria-label="Permalink to &quot;[useScreen](./composables/composables.screen.md)&quot;">​</a></h3><p>Wraps the Quasar Screen plugin with additional helpers for <code>dense</code>/<code>wide</code> breakpoints, orientation detection, and fullscreen management.</p><h3 id="uselayout" tabindex="-1"><a href="./composables/composables.layout.html">useLayout</a> <a class="header-anchor" href="#uselayout" aria-label="Permalink to &quot;[useLayout](./composables/composables.layout.md)&quot;">​</a></h3><p>Provides programmatic control over the KDK application layout. Exposes <code>configureLayout</code>, <code>clearLayout</code>, <code>setLayoutMode</code>, and per-placement pane methods for <code>top</code>, <code>left</code>, <code>bottom</code>, and <code>right</code>.</p><h2 id="activity" tabindex="-1">Activity <a class="header-anchor" href="#activity" aria-label="Permalink to &quot;Activity&quot;">​</a></h2><h3 id="useactivity-usecurrentactivity" tabindex="-1"><a href="./composables/composables.activity.html">useActivity / useCurrentActivity</a> <a class="header-anchor" href="#useactivity-usecurrentactivity" aria-label="Permalink to &quot;[useActivity / useCurrentActivity](./composables/composables.activity.md)&quot;">​</a></h3><ul><li><strong><code>useActivity(name, options)</code></strong> — sets up state and configuration stores for a named activity and registers it as the current activity.</li><li><strong><code>useCurrentActivity(options)</code></strong> — retrieves the current activity context from anywhere in the component tree.</li></ul><h2 id="collection" tabindex="-1">Collection <a class="header-anchor" href="#collection" aria-label="Permalink to &quot;Collection&quot;">​</a></h2><h3 id="usecollection" tabindex="-1"><a href="./composables/composables.collection.html">useCollection</a> <a class="header-anchor" href="#usecollection" aria-label="Permalink to &quot;[useCollection](./composables/composables.collection.md)&quot;">​</a></h3><p>Manages a reactive, paginated collection backed by a FeathersJS service using <code>feathers-reactive</code>. Supports replace-on-page and append-on-scroll strategies.</p><h3 id="usecollectioncounter" tabindex="-1"><a href="./composables/composables.collection-counter.html">useCollectionCounter</a> <a class="header-anchor" href="#usecollectioncounter" aria-label="Permalink to &quot;[useCollectionCounter](./composables/composables.collection-counter.md)&quot;">​</a></h3><p>Reactively tracks the total number of items in a FeathersJS service collection using a <code>$limit: 0</code> query.</p><h3 id="usecollectiontimerange" tabindex="-1"><a href="./composables/composables.collection-timerange.html">useCollectionTimeRange</a> <a class="header-anchor" href="#usecollectiontimerange" aria-label="Permalink to &quot;[useCollectionTimeRange](./composables/composables.collection-timerange.md)&quot;">​</a></h3><p>Reactively tracks the minimum and maximum values of a time property across a FeathersJS collection.</p><h3 id="usecollectionfilter-usecollectionfilterquery" tabindex="-1"><a href="./composables/composables.collection-filter.html">useCollectionFilter / useCollectionFilterQuery</a> <a class="header-anchor" href="#usecollectionfilter-usecollectionfilterquery" aria-label="Permalink to &quot;[useCollectionFilter / useCollectionFilterQuery](./composables/composables.collection-filter.md)&quot;">​</a></h3><ul><li><strong><code>useCollectionFilter()</code></strong> — exposes tag and time filter state from the current activity context.</li><li><strong><code>useCollectionFilterQuery(options)</code></strong> — builds a reactive <code>filterQuery</code> from active tag and time filter selections.</li></ul><h2 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h2><h3 id="useschema" tabindex="-1"><a href="./composables/composables.schema.html">useSchema</a> <a class="header-anchor" href="#useschema" aria-label="Permalink to &quot;[useSchema](./composables/composables.schema.md)&quot;">​</a></h3><p>Provides JSON Schema loading, optional property filtering, AJV compilation, and localised validation within a Vue component.</p><h2 id="errors-messages" tabindex="-1">Errors &amp; Messages <a class="header-anchor" href="#errors-messages" aria-label="Permalink to &quot;Errors &amp; Messages&quot;">​</a></h2><h3 id="useerrors" tabindex="-1"><a href="./composables/composables.errors.html">useErrors</a> <a class="header-anchor" href="#useerrors" aria-label="Permalink to &quot;[useErrors](./composables/composables.errors.md)&quot;">​</a></h3><p>Sets up a centralised error display handler. Listens to the global <code>error</code> event bus, translates messages using i18n, and displays Quasar notifications. Also handles errors embedded in route query parameters.</p><h3 id="usemessages" tabindex="-1"><a href="./composables/composables.messages.html">useMessages</a> <a class="header-anchor" href="#usemessages" aria-label="Permalink to &quot;[useMessages](./composables/composables.messages.md)&quot;">​</a></h3><p>Thin wrapper around the KDK <code>messages</code> FeathersJS service for creating messages.</p><h2 id="pwa" tabindex="-1">PWA <a class="header-anchor" href="#pwa" aria-label="Permalink to &quot;PWA&quot;">​</a></h2><h3 id="usepwa" tabindex="-1"><a href="./composables/composables.pwa.html">usePwa</a> <a class="header-anchor" href="#usepwa" aria-label="Permalink to &quot;[usePwa](./composables/composables.pwa.md)&quot;">​</a></h3><p>Manages the Progressive Web App installation prompt and service worker update lifecycle.</p><h3 id="usewelcome" tabindex="-1"><a href="./composables/composables.welcome.html">useWelcome</a> <a class="header-anchor" href="#usewelcome" aria-label="Permalink to &quot;[useWelcome](./composables/composables.welcome.md)&quot;">​</a></h3><p>Displays a welcome prompt dialog automatically after each login and hides it on logout, respecting a user preference stored in <code>LocalStorage</code>.</p>',48)])])}const p=a(r,[["render",l]]);export{u as __pageData,p as default};
